fun main() {
    val number = 7

    val type = when {
        number % 2 == 0 -> "even"
        number % 2 == 1 -> "odd"
        else -> "unknown"
    }
    println("$number is $type")

    val category = when (number) {
        in 1..10 -> "small"
        in 11..100 -> "medium"
        else -> "large"
    }
    println("Category: $category")

    fun describe(obj: Any) = when (obj) {
        is Int -> "Int: $obj"
        is String -> "String: $obj"
        else -> "Other"
    }
    println(describe(42))
    println(describe("Kotlin"))
}
